func testPaymentFlow() {
  let app = XCUIApplication()
  app.launch()
  app.buttons["Pay"].tap()
  app.textFields["Amount"].typeText("100")
  app.buttons["Confirm"].tap()
  XCTAssertTrue(app.staticTexts["Payment Successful"].exists)
}
